+                OP_LOGE(context_->opName, "%s datatype should be same with x: %s, but got %s", name.c_str(),
+                        DataTypeToSerialString(actualDtype).c_str(), DataTypeToSerialString(context_->dtype).c_str()),
+                return ge::GRAPH_FAILED);
