+struct CmpBlockInfo {
+    __aicore__ inline CmpBlockInfo(){};
+    __aicore__ inline CmpBlockInfo(uint32_t bIdx, uint32_t sIdx, bool needReset = false)
+        : bIdx(bIdx), sIdx(sIdx), needReset(needReset){};
+
+    uint32_t bIdx = 0U;
+    uint32_t sIdx = 0U;
+    uint32_t bSeqUsed = 0U;
