+    __aicore__ inline bool IsEnd();
+    __aicore__ inline void IteratorSlice();
+    __aicore__ inline SliceInfo& GetSlice();
+    __aicore__ inline SliceInfo& GetSliceByCmp();
+
+    bool isFirst_ = true;
+    SliceInfo sliceInfo_{};
+
+private:
+    CompressorTools<COMP> &tools_;
+
