+template <typename COMP>
+__aicore__ inline void CompressorSliceIterator<COMP>::Reset(uint32_t bIdx, uint32_t sIdx)
+{
+    sliceInfo_.bIdx = bIdx;
+    sliceInfo_.sIdx = sIdx;
+    isFirst_ = true;
+}
