+template <typename COMP>
+__aicore__ inline SliceInfo& CompressorSliceIterator<COMP>::GetSlice()
+{
+    uint32_t cmpRatio = tools_.toolParams_.cmpRatio;
+    if (isFirst_) {
+        sliceInfo_.bSeqUsed = tools_.GetSeqUsed(sliceInfo_.bIdx);
