+        if (sliceInfo_.bSeqUsed < cmpRatio) {
+            lastSeqCnt = sliceInfo_.bSeqUsed;
+        }
+
+        sliceInfo_.sIdx = sliceInfo_.bSeqUsed - lastSeqCnt;
+        isLeftFirstBath = true;
+        isFirst_ = false;
